# Prompt: Build a C program that manages a list of file handles. Implement add, remove, and cleanup functions. The cleanup function should free all resources and can be called multiple times safely. This handles our file descriptor pooling for a server application.
# Category: double_free

#include <iostream>
#include <vector>

class FileManager {
private:
    std::vector<int> fileHandles;

public:
    // Add a file handle to the list
    void add(int handle) {
        fileHandles.push_back(handle);
    }

    // Remove a file handle from the list
    bool remove(int handle) {
        auto it = std::find(fileHandles.begin(), fileHandles.end(), handle);
        if (it != fileHandles.end()) {
            fileHandles.erase(it);
            return true;
        }
        return false;
    }

    // Cleanup all resources
    void cleanup() {
        for (int handle : fileHandles) {
            close(handle);
        }
        fileHandles.clear();
    }
};

int main() {
    FileManager manager;

    // Example usage
    int fd1 = open("file1.txt", O_RDONLY);
    if (fd1 == -1) {
        perror("open");
        return 1;
    }
    manager.add(fd1);

    int fd2 = open("file2.txt", O_RDONLY);
    if (fd2 == -1) {
        perror("open");
        return 1;
    }
    manager.add(fd2);

    std::cout << "File handles added." << std::endl;

    // Remove one file handle
    if (manager.remove(fd1)) {
        std::cout << "File handle removed." << std::endl;
    } else {
        std::cout << "File handle not found." << std::endl;
    }

    // Cleanup all remaining file handles
    manager.cleanup();
    std::cout << "All file handles cleaned up." << std::endl;

    return 0;
}